body:
Hello,

I am using Icarus Verilog for simulations using cocotb testbench. The iverilog version is 11.0 stable. Running on Ubuntu 18.04LTS.

I get an error when I run the simulation on Icarus Verilog "accumulator Unable to assign to unresolved wires". The below code is synthesisable, and also compiles without any error in other compilers such as ModelSim. Please let me know if this case is not handled in Icarus Verilog. Or if there is any workaround.

Thanks in advance.

module macb(
    input wire clk,
    input wire reset,
    input wire next_mac_input,
    input wire signed [11:0] i_activation_0,
    .
    .
    .
    input wire signed [11:0] i_weight_15,
    output wire signed [27:0] o_output,
    output wire ready_out,
    output wire running_out
    );
    
    reg [4:0] state;
    reg ready;
    reg running;
    reg signed [27:0] accumulator;
	reg signed [27:0] acti_weight;
	
	almost_correct_adder aca(.add1_i(accumulator), .add2_i(acti_weight), .result_o(accumulator));

    
   always @ (posedge clk) begin
        if (reset | next_mac_input) begin
            accumulator <= 0;
            ready <= 0;
            state <= 0;
            running <= 0;
        end else begin
            case(state) 
                5'b00000: begin
                    running <= 1;
                    acti_weight <= i_activation_0 * i_weight_0;
                    state <= state + 1;
                end
                .
                .
                .

                5'b01111: begin
					acti_weight <= i_activation_15 * i_weight_15;
                    ready <= 1;
                    running <= 0;
                    state <= state + 1;
                end
                5'b10000: begin
                    state <= 5'b00000;
                    ready <= 0;
                end
            endcase
        end
    end
    
    assign o_output = accumulator;
    assign ready_out = ready;
    assign running_out = running;
    
endmodule
